const params = $('When Called').first().json.body.action.params;
const telegramFileId = $('When Called').first().json.body.telegram_file_id || params.telegram_file_id;
const botToken = $env.TELEGRAM_BOT_TOKEN;

// Step 1: Get file path from Telegram
const getFileRes = await fetch(`https://api.telegram.org/bot${botToken}/getFile?file_id=${telegramFileId}`);
const getFileData = await getFileRes.json();
if (!getFileData.ok) throw new Error(`Telegram getFile failed: ${JSON.stringify(getFileData)}`);

const filePath = getFileData.result.file_path;

// Step 2: Download file binary
const downloadUrl = `https://api.telegram.org/file/bot${botToken}/${filePath}`;
const fileRes = await fetch(downloadUrl);
if (!fileRes.ok) throw new Error(`Telegram file download failed: ${fileRes.status}`);

const buffer = Buffer.from(await fileRes.arrayBuffer());
const base64 = buffer.toString('base64');

return [{
  json: {
    filename: params.filename || filePath.split('/').pop() || 'archivo',
    mimeType: params.mime_type || 'application/octet-stream',
    folderId: params.folder_id || null,
    base64,
    byteLength: buffer.length,
  }
}];

const { filename, mimeType, folderId, base64 } = $input.first().json;
const accessToken = $('Get Google Token').first().json.access_token;

// Build multipart body for Drive upload
const boundary = `drive_upload_${Date.now()}`;
const metadata = { name: filename };
if (folderId) metadata.parents = [folderId];

const metadataJson = JSON.stringify(metadata);
const fileBuffer = Buffer.from(base64, 'base64');

// Build raw multipart body
const parts = [
  `--${boundary}`,
  `Content-Type: application/json; charset=UTF-8`,
  ``,
  metadataJson,
  `--${boundary}`,
  `Content-Type: ${mimeType}`,
  `Content-Transfer-Encoding: base64`,
  ``,
  base64,
  `--${boundary}--`,
].join('\r\n');

const uploadRes = await fetch(
  'https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart&fields=id,name,webViewLink,webContentLink',
  {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${accessToken}`,
      'Content-Type': `multipart/related; boundary=${boundary}`,
    },
    body: parts,
  }
);

if (!uploadRes.ok) {
  const err = await uploadRes.text();
  throw new Error(`Drive upload failed: ${uploadRes.status} — ${err}`);
}

const file = await uploadRes.json();

// Set file to be viewable by anyone with the link (optional — comment out if not needed)
await fetch(`https://www.googleapis.com/drive/v3/files/${file.id}/permissions`, {
  method: 'POST',
  headers: {
    Authorization: `Bearer ${accessToken}`,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({ role: 'reader', type: 'anyone' }),
});

return [{ json: { success: true, file_id: file.id, file_name: file.name, view_link: file.webViewLink, download_link: file.webContentLink } }];

const params = $('When Called').first().json.body.action.params;
const accessToken = $('Get Google Token').first().json.access_token;
const query = params.query || '';
const maxResults = params.max_results || 5;

const encodedQuery = encodeURIComponent(`name contains '${query.replace(/'/g, "\\'")}'`);
const url = `https://www.googleapis.com/drive/v3/files?q=${encodedQuery}&fields=files(id,name,mimeType,webViewLink,modifiedTime)&pageSize=${maxResults}&orderBy=modifiedTime desc`;

const res = await fetch(url, { headers: { Authorization: `Bearer ${accessToken}` } });
if (!res.ok) throw new Error(`Drive search failed: ${res.status}`);

const data = await res.json();
return [{ json: { success: true, files: data.files || [] } }];
